'use client';
import { createClient } from '@/utils/supabase/client';
import { useEffect, useState } from 'react';
import Link from 'next/link';
import { ArrowLeft, Package, Calendar, DollarSign, MapPin, FileText } from 'lucide-react';
import { useParams } from 'next/navigation';

export default function OrderDetailsPage() {
    const { id } = useParams();
    const [order, setOrder] = useState(null);
    const [loading, setLoading] = useState(true);
    const supabase = createClient();

    useEffect(() => {
        async function fetchOrderDetails() {
            if (!id) return;

            const { data, error } = await supabase
                .from('orders')
                .select(`
          *,
          order_items (
            *,
            products (
              name,
              sku,
              image_url
            )
          )
        `)
                .eq('id', id)
                .single();

            if (error) {
                console.error('Error fetching order:', error);
            } else {
                setOrder(data);
            }
            setLoading(false);
        }

        fetchOrderDetails();
    }, [id]);

    if (loading) {
        return (
            <div className="loading-container">
                <div className="spinner"></div>
                <p>Cargando detalles del pedido...</p>
            </div>
        );
    }

    if (!order) {
        return (
            <div className="error-container">
                <p>No se encontró el pedido o no tienes permiso para verlo.</p>
                <Link href="/dashboard/pedidos" className="btn btn-primary">Volver a Pedidos</Link>
            </div>
        );
    }

    return (
        <div className="details-container">
            <div className="page-header">
                <Link href="/dashboard/pedidos" className="back-link">
                    <ArrowLeft size={20} />
                    Volver
                </Link>
                <div className="header-title">
                    <h1>Pedido #{order.order_number}</h1>
                    <span className={`status-badge ${order.status}`}>{order.status}</span>
                </div>
            </div>

            <div className="details-grid">
                {/* Order Info & Items */}
                <div className="main-content">
                    <div className="glass-panel items-list">
                        <h3>Productos en el Pedido</h3>
                        <table className="items-table">
                            <thead>
                                <tr>
                                    <th>Producto</th>
                                    <th>Precio Unitario</th>
                                    <th>Cantidad</th>
                                    <th>Subtotal</th>
                                </tr>
                            </thead>
                            <tbody>
                                {order.order_items.map((item) => (
                                    <tr key={item.id}>
                                        <td>
                                            <div className="product-info">
                                                <div className="product-thumb">
                                                    {item.products.image_url ? (
                                                        <img src={item.products.image_url} alt={item.products.name} />
                                                    ) : (
                                                        <Package size={24} color="#aaa" />
                                                    )}
                                                </div>
                                                <div>
                                                    <div className="product-name">{item.products.name}</div>
                                                    <div className="product-sku">SKU: {item.products.sku}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td>${item.unit_price}</td>
                                        <td>{item.quantity}</td>
                                        <td className="subtotal">${item.subtotal}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* Order Summary Sidebar */}
                <div className="sidebar-info">
                    <div className="glass-panel summary-card">
                        <h3>Resumen</h3>

                        <div className="summary-row date">
                            <div className="icon"><Calendar size={18} /></div>
                            <div>
                                <label>Fecha del Pedido</label>
                                <div>{new Date(order.created_at).toLocaleDateString()} {new Date(order.created_at).toLocaleTimeString()}</div>
                            </div>
                        </div>

                        <div className="summary-row total">
                            <div className="icon"><DollarSign size={18} /></div>
                            <div>
                                <label>Total</label>
                                <div className="amount">${order.total_amount}</div>
                            </div>
                        </div>

                        {order.notes && (
                            <div className="summary-row notes">
                                <div className="icon"><FileText size={18} /></div>
                                <div>
                                    <label>Notas</label>
                                    <div>{order.notes}</div>
                                </div>
                            </div>
                        )}

                        {order.shipping_address && (
                            <div className="summary-row address">
                                <div className="icon"><MapPin size={18} /></div>
                                <div>
                                    <label>Dirección de Envío</label>
                                    <div>{order.shipping_address}</div>
                                </div>
                            </div>
                        )}

                        {/* Actions for Admin (placeholder) */}
                        {/* 
            <div className="admin-actions">
              <button className="btn btn-outline-light btn-block btn-sm">Marcar como Enviado</button>
            </div> 
            */}
                    </div>
                </div>
            </div>

            <style jsx>{`
        .details-container {
          max-width: 1200px;
          margin: 0 auto;
        }

        .loading-container, .error-container {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          min-height: 50vh;
          color: var(--color-text-muted);
          gap: 1rem;
        }
        
        .spinner {
          border: 3px solid rgba(255,255,255,0.1);
          border-left-color: var(--color-primary);
          border-radius: 50%;
          width: 40px;
          height: 40px;
          animation: spin 1s linear infinite;
        }

        @keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

        .page-header {
          margin-bottom: 2rem;
        }

        .back-link {
          display: inline-flex;
          align-items: center;
          gap: 0.5rem;
          color: var(--color-text-muted);
          text-decoration: none;
          margin-bottom: 1rem;
          font-size: 0.9rem;
          transition: color 0.2s;
        }
        .back-link:hover { color: white; }

        .header-title {
          display: flex;
          align-items: center;
          gap: 1.5rem;
        }

        .header-title h1 {
          font-size: 2rem;
          margin: 0;
          color: white;
        }

        .status-badge {
          padding: 0.25rem 0.75rem;
          border-radius: 99px;
          font-size: 0.85rem;
          font-weight: 700;
          text-transform: uppercase;
        }
        .status-badge.pending { background: rgba(234, 179, 8, 0.2); color: #fbbf24; }
        .status-badge.processing { background: rgba(59, 130, 246, 0.2); color: #60a5fa; }
        .status-badge.shipped { background: rgba(34, 197, 94, 0.2); color: #4ade80; }
        .status-badge.delivered { background: rgba(16, 185, 129, 0.2); color: #34d399; }
        .status-badge.cancelled { background: rgba(239, 68, 68, 0.2); color: #fca5a5; }

        .details-grid {
          display: grid;
          grid-template-columns: 1fr 350px;
          gap: 2rem;
        }

        .glass-panel {
          padding: 1.5rem;
        }

        .items-list h3, .summary-card h3 {
          margin-top: 0;
          margin-bottom: 1.5rem;
          font-size: 1.1rem;
          color: white;
          border-bottom: 1px solid rgba(255,255,255,0.1);
          padding-bottom: 0.75rem;
        }

        .items-table {
          width: 100%;
          border-collapse: collapse;
          color: white;
        }

        .items-table th {
          text-align: left;
          padding: 0.75rem;
          color: var(--color-text-muted);
          font-weight: 500;
          font-size: 0.85rem;
          border-bottom: 1px solid rgba(255,255,255,0.05);
        }

        .items-table td {
          padding: 1rem 0.75rem;
          border-bottom: 1px solid rgba(255,255,255,0.05);
          vertical-align: middle;
        }

        .product-info {
          display: flex;
          align-items: center;
          gap: 1rem;
        }

        .product-thumb {
          width: 48px;
          height: 48px;
          background: rgba(255,255,255,0.05);
          border-radius: 8px;
          display: flex;
          align-items: center;
          justify-content: center;
          overflow: hidden;
        }
        .product-thumb img {
          width: 100%;
          height: 100%;
          object-fit: cover;
        }

        .product-name {
          font-weight: 500;
          color: white;
        }
        .product-sku {
          font-size: 0.75rem;
          color: var(--color-text-muted);
        }

        .subtotal {
          font-weight: 600;
          color: var(--color-primary);
        }

        .summary-row {
          display: flex;
          gap: 1rem;
          margin-bottom: 1.5rem;
        }

        .summary-row .icon {
          color: var(--color-primary);
          margin-top: 0.25rem;
        }

        .summary-row label {
          display: block;
          font-size: 0.8rem;
          color: var(--color-text-muted);
          margin-bottom: 0.25rem;
        }

        .summary-row div:last-child {
          color: white;
          font-size: 0.95rem;
        }

        .summary-row.total .amount {
          font-size: 1.5rem;
          font-weight: 700;
          color: var(--color-primary);
        }

        @media (max-width: 900px) {
          .details-grid {
            grid-template-columns: 1fr;
          }
        }
      `}</style>
        </div>
    );
}
